import math

def realcompare(a: float, b: float) -> str:
    """
    Compares two real numbers based on the six most significant digits.
    Returns 'LT', 'EQ', or 'GT'.
    """
    if a == b:
        return "EQ"

    def round_to_6_sig_figs(x):
        if x == 0:
            return 0.0
        mag = math.floor(math.log10(abs(x)))
        return round(x, -int(mag) + 5)

    ra = round_to_6_sig_figs(a)
    rb = round_to_6_sig_figs(b)

    if ra < rb:
        return "LT"
    elif ra > rb:
        return "GT"
    else:
        return "EQ"

def decide(numpoints: int, x: list[float], y: list[float], parameters: dict, lcm: list[list[str]], pum_diag: list[bool]) -> tuple:
    PI = 3.1415926535
    cmv = [False] * 15

    def dist(i, j):
        return math.sqrt((x[i] - x[j])**2 + (y[i] - y[j])**2)

    def get_sec_radius(p1, p2, p3):
        a2 = (p2[0]-p3[0])**2 + (p2[1]-p3[1])**2
        b2 = (p1[0]-p3[0])**2 + (p1[1]-p3[1])**2
        c2 = (p1[0]-p2[0])**2 + (p1[1]-p2[1])**2
        if a2 + b2 <= c2: return math.sqrt(c2)/2
        if a2 + c2 <= b2: return math.sqrt(b2)/2
        if b2 + c2 <= a2: return math.sqrt(a2)/2
        a, b, c = math.sqrt(a2), math.sqrt(b2), math.sqrt(c2)
        area = 0.5 * abs(p1[0]*(p2[1]-p3[1]) + p2[0]*(p3[1]-p1[1]) + p3[0]*(p1[1]-p2[1]))
        if area == 0: return max(a, b, c) / 2
        return (a * b * c) / (4 * area)

    # LIC 1
    for i in range(numpoints - 1):
        if realcompare(dist(i, i+1), parameters['LENGTH1']) == "GT":
            cmv[0] = True
            break

    # LIC 2
    for i in range(numpoints - 2):
        pts = [(x[i], y[i]), (x[i+1], y[i+1]), (x[i+2], y[i+2])]
        if realcompare(get_sec_radius(pts[0], pts[1], pts[2]), parameters['RADIUS1']) == "GT":
            cmv[1] = True
            break

    # LIC 3
    for i in range(numpoints - 2):
        p1, v, p2 = (x[i], y[i]), (x[i+1], y[i+1]), (x[i+2], y[i+2])
        if (p1[0], p1[1]) == v or (p2[0], p2[1]) == v: continue
        v1, v2 = (p1[0]-v[0], p1[1]-v[1]), (p2[0]-v[0], p2[1]-v[1])
        dot = v1[0]*v2[0] + v1[1]*v2[1]
        m1, m2 = math.sqrt(v1[0]**2 + v1[1]**2), math.sqrt(v2[0]**2 + v2[1]**2)
        angle = math.acos(max(-1.0, min(1.0, dot / (m1 * m2))))
        if realcompare(angle, PI - parameters['EPSILON']) == "LT" or \
           realcompare(angle, PI + parameters['EPSILON']) == "GT":
            cmv[2] = True
            break

    # LIC 4
    for i in range(numpoints - 2):
        area = 0.5 * abs(x[i]*(y[i+1]-y[i+2]) + x[i+1]*(y[i+2]-y[i]) + x[i+2]*(y[i]-y[i+1]))
        if realcompare(area, parameters['AREA1']) == "GT":
            cmv[3] = True
            break

    # LIC 5
    def get_quadrant(px, py):
        if px >= 0 and py >= 0: return 1
        if px < 0 and py >= 0: return 2
        if px <= 0 and py < 0: return 3
        return 4

    q_pts = parameters['Q_PTS']
    quads_limit = parameters['QUADS']
    for i in range(numpoints - q_pts + 1):
        qs = {get_quadrant(x[j], y[j]) for j in range(i, i + q_pts)}
        if len(qs) > quads_limit:
            cmv[4] = True
            break

    # LIC 6
    for i in range(numpoints - 1):
        if realcompare(x[i+1] - x[i], 0) == "LT":
            cmv[5] = True
            break

    # LIC 7
    n_pts_7 = parameters['N_PTS']
    dist_7 = parameters['DIST']
    if numpoints >= 3:
        for i in range(numpoints - n_pts_7 + 1):
            p1, p2 = (x[i], y[i]), (x[i + n_pts_7 - 1], y[i + n_pts_7 - 1])
            found = False
            if p1 == p2:
                for j in range(i, i + n_pts_7):
                    if realcompare(dist(i, j), dist_7) == "GT":
                        found = True; break
            else:
                A, B, C = p2[1]-p1[1], p1[0]-p2[0], p2[0]*p1[1]-p2[1]*p1[0]
                denom = math.sqrt(A**2 + B**2)
                for j in range(i, i + n_pts_7):
                    if realcompare(abs(A*x[j] + B*y[j] + C) / denom, dist_7) == "GT":
                        found = True; break
            if found:
                cmv[6] = True; break

    # LIC 8
    k_pts = parameters['K_PTS']
    if numpoints >= 3:
        for i in range(numpoints - k_pts - 1):
            if realcompare(dist(i, i + k_pts + 1), parameters['LENGTH1']) == "GT":
                cmv[7] = True; break

    # LIC 9
    a_pts, b_pts = parameters['A_PTS'], parameters['B_PTS']
    if numpoints >= 5:
        for i in range(numpoints - (a_pts + b_pts + 2)):
            idx = [i, i + a_pts + 1, i + a_pts + b_pts + 2]
            pts = [(x[j], y[j]) for j in idx]
            if realcompare(get_sec_radius(pts[0], pts[1], pts[2]), parameters['RADIUS1']) == "GT":
                cmv[8] = True; break

    # LIC 10
    c_pts, d_pts = parameters['C_PTS'], parameters['D_PTS']
    if numpoints >= 5:
        for i in range(numpoints - (c_pts + d_pts + 2)):
            idx = [i, i + c_pts + 1, i + c_pts + d_pts + 2]
            p1, v, p2 = (x[idx[0]], y[idx[0]]), (x[idx[1]], y[idx[1]]), (x[idx[2]], y[idx[2]])
            if p1 == v or p2 == v: continue
            v1, v2 = (p1[0]-v[0], p1[1]-v[1]), (p2[0]-v[0], p2[1]-v[1])
            dot = v1[0]*v2[0] + v1[1]*v2[1]
            m1, m2 = math.sqrt(v1[0]**2 + v1[1]**2), math.sqrt(v2[0]**2 + v2[1]**2)
            angle = math.acos(max(-1.0, min(1.0, dot / (m1 * m2))))
            if realcompare(angle, PI - parameters['EPSILON']) == "LT" or \
               realcompare(angle, PI + parameters['EPSILON']) == "GT":
                cmv[9] = True; break

    # LIC 11
    e_pts, f_pts = parameters['E_PTS'], parameters['F_PTS']
    if numpoints >= 5:
        for i in range(numpoints - (e_pts + f_pts + 2)):
            idx = [i, i + e_pts + 1, i + e_pts + f_pts + 2]
            area = 0.5 * abs(x[idx[0]]*(y[idx[1]]-y[idx[2]]) + x[idx[1]]*(y[idx[2]]-y[idx[0]]) + x[idx[2]]*(y[idx[0]]-y[idx[1]]))
            if realcompare(area, parameters['AREA1']) == "GT":
                cmv[10] = True; break

    # LIC 12
    g_pts = parameters['G_PTS']
    if numpoints >= 3:
        for i in range(numpoints - g_pts - 1):
            if realcompare(x[i + g_pts + 1] - x[i], 0) == "LT":
                cmv[11] = True; break

    # LIC 13
    if numpoints >= 3:
        c1 = any(realcompare(dist(i, i+k_pts+1), parameters['LENGTH1']) == "GT" for i in range(numpoints - k_pts - 1))
        c2 = any(realcompare(dist(i, i+k_pts+1), parameters['LENGTH2']) == "LT" for i in range(numpoints - k_pts - 1))
        if c1 and c2: cmv[12] = True

    # LIC 14
    if numpoints >= 5:
        c1 = any(realcompare(get_sec_radius((x[i],y[i]), (x[i+a_pts+1],y[i+a_pts+1]), (x[i+a_pts+b_pts+2],y[i+a_pts+b_pts+2])), parameters['RADIUS1']) == "GT" for i in range(numpoints - (a_pts+b_pts+2)))
        c2 = any(realcompare(get_sec_radius((x[i],y[i]), (x[i+a_pts+1],y[i+a_pts+1]), (x[i+a_pts+b_pts+2],y[i+a_pts+b_pts+2])), parameters['RADIUS2']) == "LT" for i in range(numpoints - (a_pts+b_pts+2)))
        if c1 and c2: cmv[13] = True

    # LIC 15
    if numpoints >= 5:
        c1 = False
        for i in range(numpoints - (e_pts + f_pts + 2)):
            idx = [i, i + e_pts + 1, i + e_pts + f_pts + 2]
            area = 0.5 * abs(x[idx[0]]*(y[idx[1]]-y[idx[2]]) + x[idx[1]]*(y[idx[2]]-y[idx[0]]) + x[idx[2]]*(y[idx[0]]-y[idx[1]]))
            if realcompare(area, parameters['AREA1']) == "GT":
                c1 = True; break
        c2 = False
        for i in range(numpoints - (e_pts + f_pts + 2)):
            idx = [i, i + e_pts + 1, i + e_pts + f_pts + 2]
            area = 0.5 * abs(x[idx[0]]*(y[idx[1]]-y[idx[2]]) + x[idx[1]]*(y[idx[2]]-y[idx[0]]) + x[idx[2]]*(y[idx[0]]-y[idx[1]]))
            if realcompare(area, parameters['AREA2']) == "LT":
                c2 = True; break
        if c1 and c2: cmv[14] = True

    # PUM
    pum = [[False]*15 for _ in range(15)]
    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = pum_diag[i]
            else:
                conn = lcm[i][j]
                if conn == "NOTUSED":
                    pum[i][j] = True
                elif conn == "ANDD":
                    pum[i][j] = cmv[i] and cmv[j]
                elif conn == "ORR":
                    pum[i][j] = cmv[i] or cmv[j]

    # FUV
    fuv = [False] * 15
    for i in range(15):
        if not pum_diag[i]:
            fuv[i] = True
        else:
            if all(pum[i][j] for j in range(15)):
                fuv[i] = True

    # LAUNCH
    launch = all(fuv)

    return (cmv, pum, fuv, launch)
